CHAT_PATCH_PY = '"""\nLógica para patchar /v2/chat/page.tsx:\n1. Adicionar leitura do sessionStorage \'planta-pending-image\' no mount.\n2. Se houver imagem, criar uma mensagem \'user\' com a imagem inline.\n3. No render, se message.content contém \'data:image/\' inline, renderizar <img>.\n\nPattern de detecção (do v12b):\n  - `setMessages(loadHistory());` no useEffect inicial\n  - `messages.map((m, i) =>` no render\n"""\nimport re\n\nATTACH_HANDLER = """    setMessages(loadHistory());\n    // v20: aceitar imagem anexada via sessionStorage\n    try {\n      const raw = sessionStorage.getItem(\'planta-pending-image\');\n      if (raw) {\n        const data = JSON.parse(raw);\n        sessionStorage.removeItem(\'planta-pending-image\');\n        if (data && data.dataUrl) {\n          const imgMsg = {\n            role: \'user\',\n            content: data.dataUrl,\n            ts: Date.now(),\n          };\n          setMessages((prev) => [...prev, imgMsg]);\n        }\n      }\n    } catch {}"""\n\nIMAGE_RENDER_HELPER = """\nfunction isImageDataUrl(s: string): boolean {\n  return typeof s === \'string\' && s.startsWith(\'data:image/\');\n}\n"""\n\ndef patch_chat_page(content: str) -> tuple[str, list[str]]:\n    """Aplica patches. Devolve (novo_conteudo, lista_de_mudanças)."""\n    changes = []\n    \n    # Idempotente\n    if \'planta-pending-image\' in content:\n        return content, [\'ja aplicado, skip\']\n    \n    # 1. Procurar `setMessages(loadHistory());` e adicionar handling do attach a seguir\n    if \'setMessages(loadHistory());\' in content:\n        content = content.replace(\n            \'setMessages(loadHistory());\',\n            ATTACH_HANDLER.strip(),\n            1,\n        )\n        changes.append(\'attach handler adicionado\')\n    else:\n        changes.append(\'WARN: setMessages(loadHistory()) nao encontrado\')\n        return content, changes\n    \n    # 2. Adicionar helper isImageDataUrl no topo (fora do componente)\n    # Procuro depois do `function saveHistory(msgs: Msg[])` block\n    if \'function saveHistory\' in content and \'isImageDataUrl\' not in content:\n        # Insert antes do `export default function`\n        m = re.search(r\'export default function \\w+\', content)\n        if m:\n            content = content[:m.start()] + IMAGE_RENDER_HELPER + \'\\n\' + content[m.start():]\n            changes.append(\'helper isImageDataUrl adicionado\')\n    \n    # 3. Substituir o conteúdo do bubble da mensagem\n    # Procuro `{m.content}` dentro de um div com background m.role\n    # Padrão típico do v12b:\n    #   >\n    #             {m.content}\n    #           </div>\n    old_render = \'{m.content}\'\n    new_render = \'{isImageDataUrl(m.content) ? (\\n              <ImageBubble src={m.content} />\\n            ) : (\\n              m.content\\n            )}\'\n    \n    if old_render in content:\n        content = content.replace(old_render, new_render, 1)\n        changes.append(\'render condicional de imagem adicionado\')\n    \n    # 4. Adicionar componente ImageBubble no fim do ficheiro\n    if \'function ImageBubble\' not in content:\n        bubble_component = \'\'\'\nfunction ImageBubble({ src }: { src: string }) {\n  const filename = `planta-${Date.now()}.png`;\n  return (\n    <div style={{ display: \'flex\', flexDirection: \'column\', gap: 6 }}>\n      <img\n        src={src}\n        alt="imagem anexada"\n        style={{\n          maxWidth: \'100%\',\n          maxHeight: 360,\n          borderRadius: 12,\n          display: \'block\',\n        }}\n      />\n      <a\n        href={src}\n        download={filename}\n        style={{\n          fontSize: 11,\n          color: \'rgba(255,255,255,0.85)\',\n          textDecoration: \'underline\',\n          textAlign: \'right\',\n          fontFamily: \'var(--font-mono)\',\n          letterSpacing: \'0.04em\',\n        }}\n      >\n        ⬇ guardar\n      </a>\n    </div>\n  );\n}\n\'\'\'\n        content = content.rstrip() + \'\\n\' + bubble_component\n        changes.append(\'ImageBubble componente adicionado\')\n    \n    return content, changes\n\n\nif __name__ == \'__main__\':\n    import sys\n    src = sys.argv[1] if len(sys.argv) > 1 else None\n    if not src:\n        print(\'Usage: python chat_patch_logic.py <path-to-chat-page.tsx>\')\n        sys.exit(1)\n    from pathlib import Path\n    p = Path(src)\n    new, changes = patch_chat_page(p.read_text())\n    p.write_text(new)\n    print(\'\\n\'.join(changes))\n'


def sec(m):
    print()
    print("=" * 68)
    print("  " + m)
    print("=" * 68)


def run(cmd, cwd=None):
    print(f"$ {cmd}")
    r = subprocess.run(cmd, shell=True, cwd=cwd, capture_output=True, text=True)
    if r.stdout.strip(): print(r.stdout.rstrip())
    if r.stderr.strip(): print(r.stderr.rstrip(), file=sys.stderr)
    return r.returncode == 0


def patch_home_footer(root, stamp):
    """Remove '— Planta' do footer do /v2/page.tsx (post-v19)."""
    p = root / "frontend" / "app" / "v2" / "page.tsx"
    if not p.exists():
        print("  WARN: page.tsx nao encontrado")
        return False
    c = p.read_text()
    
    if "FCT 2025.00020.AIVLAB.DEUCALION" in c:
        # v19 nunca foi aplicado — aplica directamente sem o "— Planta"
        old = (
            '        <div className="mono" style={{ fontSize: 10.5, letterSpacing: \'0.12em\', textTransform: \'uppercase\' }}>\n'
            '          FCT 2025.00020.AIVLAB.DEUCALION\n'
            '        </div>'
        )
        new = (
            '        <div style={{\n'
            '          fontSize: \'clamp(12px, 1.3vw, 14px)\',\n'
            '          color: \'var(--muted)\',\n'
            '          fontStyle: \'italic\',\n'
            '          letterSpacing: \'-0.005em\',\n'
            '          maxWidth: \'60ch\',\n'
            '          lineHeight: 1.4,\n'
            '        }}>\n'
            '          Someone has to take care of your needs.\n'
            '        </div>'
        )
        if old in c:
            shutil.copy2(p, p.with_suffix(f".tsx.bak.v20.{stamp}"))
            c = c.replace(old, new)
            p.write_text(c)
            print("  OK footer FCT substituido por tagline editorial (sem '— Planta')")
            return True
    
    # v19 ja foi aplicado — remover so o span '— Planta'
    if "Someone has to take care of your needs" in c and "— Planta" in c:
        shutil.copy2(p, p.with_suffix(f".tsx.bak.v20.{stamp}"))
        # Regex para remover qualquer <span ...>— Planta</span>
        new_c = re.sub(
            r'\s*<span\s+style=\{\{[^}]*?\}\}>—\s*Planta</span>',
            '',
            c,
            flags=re.DOTALL,
        )
        if new_c == c:
            new_c = re.sub(
                r'\s*<span[^>]*>—\s*Planta</span>',
                '',
                c,
            )
        if new_c != c:
            p.write_text(new_c)
            print("  OK '— Planta' removido do footer")
            return True
        print("  WARN: nao encontrei o span '— Planta' por regex")
        return False
    
    if "Someone has to take care" in c and "— Planta" not in c:
        print("  i tagline ja sem '— Planta', skip")
        return True
    
    print("  WARN: nao encontrei nem FCT nem tagline para patchar")
    return False


def patch_chat_page(root, stamp):
    """Aplica patches ao /v2/chat/page.tsx para mostrar imagens anexadas."""
    p = root / "frontend" / "app" / "v2" / "chat" / "page.tsx"
    if not p.exists():
        print("  WARN: chat page nao encontrado")
        return False
    c = p.read_text()
    
    # Executar logica do patch (definida em CHAT_PATCH_PY como string)
    # Aqui re-implementamos directamente
    if 'planta-pending-image' in c:
        print("  i chat patch ja aplicado")
        return True
    
    if 'setMessages(loadHistory());' not in c:
        print("  WARN: chat page nao tem marker 'setMessages(loadHistory())' — formato diferente")
        return False
    
    shutil.copy2(p, p.with_suffix(f".tsx.bak.v20.{stamp}"))
    
    # 1. Attach handler
    attach_handler = """setMessages(loadHistory());
    // v20: aceitar imagem anexada via sessionStorage
    try {
      const raw = sessionStorage.getItem('planta-pending-image');
      if (raw) {
        const data = JSON.parse(raw);
        sessionStorage.removeItem('planta-pending-image');
        if (data && data.dataUrl) {
          const imgMsg = {
            role: 'user' as const,
            content: data.dataUrl,
            ts: Date.now(),
          };
          setMessages((prev) => [...prev, imgMsg]);
        }
      }
    } catch {}"""
    c = c.replace('setMessages(loadHistory());', attach_handler, 1)
    
    # 2. Helper function antes do componente
    if 'isImageDataUrl' not in c:
        helper = """
function isImageDataUrl(s: string): boolean {
  return typeof s === 'string' && s.startsWith('data:image/');
}
"""
        m = re.search(r'(export default function \w+)', c)
        if m:
            c = c[:m.start()] + helper + '\n' + c[m.start():]
    
    # 3. Render condicional
    if '{m.content}' in c:
        c = c.replace(
            '{m.content}',
            '{isImageDataUrl(m.content) ? (\n              <ImageBubble src={m.content} />\n            ) : (\n              m.content\n            )}',
            1,
        )
    
    # 4. Componente ImageBubble no fim
    if 'function ImageBubble' not in c:
        bubble = """
function ImageBubble({ src }: { src: string }) {
  const filename = `planta-${Date.now()}.png`;
  return (
    <div style={{ display: 'flex', flexDirection: 'column', gap: 6 }}>
      <img
        src={src}
        alt="imagem anexada"
        style={{
          maxWidth: '100%',
          maxHeight: 360,
          borderRadius: 12,
          display: 'block',
        }}
      />
      <a
        href={src}
        download={filename}
        style={{
          fontSize: 11,
          color: 'rgba(255,255,255,0.85)',
          textDecoration: 'underline',
          textAlign: 'right',
          fontFamily: 'var(--font-mono)',
          letterSpacing: '0.04em',
        }}
      >
        ⬇ guardar
      </a>
    </div>
  );
}
"""
        c = c.rstrip() + '\n' + bubble
    
    p.write_text(c)
    print(f"  OK chat page patched (+ImageBubble +sessionStorage)")
    return True


